import React from 'react';
import styled from 'styled-components';
import { Link } from 'react-router-dom';
import Button from '../components/common/Button';
import Container from '../components/common/Container';

const HomePage = () => {
  return (
    <Container>
      <Hero>
        <h1>Turn "It was good" into testimonials that actually sell</h1>
        <p>AI-powered testimonial enhancement with client verification</p>
        <ButtonContainer>
          <Link to="/enhance">
            <Button primary>Get Started - It's Free</Button>
          </Link>
          <Link to="/pricing">
            <Button>See Pricing</Button>
          </Link>
        </ButtonContainer>
      </Hero>

      <HowItWorks>
        <h2>How It Works</h2>
        <Steps>
          <Step>
            <h3>1. Submit raw testimonial</h3>
            <p>Paste your client's words or upload audio</p>
          </Step>
          <Step>
            <h3>2. Get AI-enhanced version</h3>
            <p>Our AI extracts transformation, emotion, and impact</p>
          </Step>
          <Step>
            <h3>3. One-click client approval</h3>
            <p>Send a link, client confirms with one click</p>
          </Step>
        </Steps>
      </HowItWorks>

      <BeforeAfter>
        <h2>Before & After</h2>
        {/* Example testimonials side by side */}
        <TestimonialComparison>
          <Testimonial original>
            <h4>Original</h4>
            <p>"The coaching was good. I learned some things that helped me."</p>
          </Testimonial>
          <Testimonial>
            <h4>Enhanced</h4>
            <p>"Working with Sarah transformed how I approach challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible."</p>
          </Testimonial>
        </TestimonialComparison>
      </BeforeAfter>
    </Container>
  );
};

// Styled components here...
const Hero = styled.div`
  text-align: center;
  padding: 80px 0;
`;

const ButtonContainer = styled.div`
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-top: 32px;
`;

const HowItWorks = styled.section`
  margin: 80px 0;
  text-align: center;
`;

const Steps = styled.div`
  display: flex;
  gap: 32px;
  margin-top: 40px;

  @media (max-width: 768px) {
    flex-direction: column;
  }
`;

const Step = styled.div`
  flex: 1;
  padding: 24px;
  border-radius: 8px;
  background: #f7f9fc;
`;

const BeforeAfter = styled.section`
  margin: 80px 0;
  text-align: center;
`;

const TestimonialComparison = styled.div`
  display: flex;
  gap: 32px;
  margin-top: 40px;

  @media (max-width: 768px) {
    flex-direction: column;
  }
`;

const Testimonial = styled.div`
  flex: 1;
  padding: 32px;
  border-radius: 8px;
  background: ${props => props.original ? '#f7f9fc' : '#ebf3ff'};
  text-align: left;
`;

export default HomePage;
